def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[idx] = np.inf
            continue
        base_ratio = item / cap
        if base_ratio >= 2:
            priorities[idx] = np.inf
            continue
        total_score = 0.0
        complexity_factor = 1.0
        decay = 1.0
        oscillation = 0.5
        modifier = 1.0
        gradient = 0.0
        nested_sum = 0.0
        for outer in range(1, 15):
            if outer % 4 == 0:
                complexity_factor *= 1.07 - 0.02 * (outer / 10)
            elif outer % 6 == 0:
                complexity_factor *= 0.93 + 0.01 * (outer / 15)
            ratio_mod = base_ratio + (outer * 0.03)
            if ratio_mod < 0.5:
                part = np.tanh(ratio_mod * outer) * (outer ** 1.5)
                total_score += part * complexity_factor
                gradient += np.cos(ratio_mod * outer * 2) * 0.1 * outer
            else:
                denom = 1 + np.exp(-0.1 * (outer - base_ratio*20))
                part = (np.log1p(outer * outer) * np.sqrt(ratio_mod)) / denom
                total_score += part * complexity_factor * 0.8
                gradient -= np.sin(base_ratio * outer) * 0.05 * outer
            if (cap * outer) % 9 == 0:
                total_score *= 1.03
            elif (cap + outer) % 11 == 0:
                total_score *= 0.97
            for inner in range(1, outer//2 + 2):
                val = ((cap / (inner + 1)) - item * inner) ** 2
                if val <= 0:
                    nested_sum -= np.sqrt(abs(val)) * (inner + 1) * 0.03
                else:
                    nested_sum += np.log1p(val) / (inner + 2) * 0.07
            decay *= 1 - 0.01 * (outer % 5)
            oscillation += np.sin(outer + base_ratio) * 0.02
            if outer == 10:
                modifier += gradient * 0.1 - nested_sum * 0.05
        modifier = max(0.5, min(1.5, modifier))
        score_adj = total_score * decay * oscillation * modifier
        if score_adj < 0:
            priority = -score_adj * (np.sqrt(cap) + base_ratio) * (1 + nested_sum)
        else:
            if cap > item * 3:
                priority = -score_adj / (cap ** 0.75 + 1) * (1 + base_ratio * 0.5)
            else:
                priority = -score_adj / (cap + 5) * np.exp(-base_ratio**1.5)
        if base_ratio > 0.9:
            priority *= 1.2
        elif base_ratio < 0.1:
            priority *= 0.7
        if int(cap) % 3 == 0:
            priority *= 0.95
        elif int(cap) % 4 == 1:
            priority *= 1.03
        if item % 2 == 0:
            priority *= 1.01
        else:
            priority *= 0.99
        priorities[idx] = priority
    return priorities
